mapper.sql:
SELECT
ID,
CNDN_CODE,
COMPANY_ID,
COMPANY_NAME,
TAXATION_INVOICE_CODE,
TAXATION_INVOICE,
CNDN_BILL_TYPE_CODE,
CNDN_BILL_TYPE_NAME,
INVOICE_CODE,
CUSTOMER_ID,
CUSTOMER_NAME,
SYS_INVOICE_CODE,
ELIMINATE_AMOUNT,
REMARK,
CNDN_TYPE,
CNDN_TIME,
STATUS,
VOID_REASON,
VOID_REMARK,
IS_DEBTOR_PAYMENT,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_FD_CREDIT_DEBIT_BILL


        and ID = #{id}


        and COMPANY_ID = #{companyId}


        and CNDN_CODE = #{cndnCode}


        and COMPANY_NAME = #{companyName}


        and TAXATION_INVOICE_CODE = #{taxationInvoiceCode}


        and TAXATION_INVOICE = #{taxationInvoice}


        and CNDN_BILL_TYPE_CODE = #{cndnBillTypeCode}


        and CNDN_BILL_TYPE_NAME = #{cndnBillTypeName}


        and INVOICE_CODE = #{invoiceCode}


        and CUSTOMER_ID = #{customerId}


        and CUSTOMER_NAME = #{customerName}


        and SYS_INVOICE_CODE = #{sysInvoiceCode}


        and ELIMINATE_AMOUNT = #{eliminateAmount}


        and REMARK = #{remark}


        and CNDN_TYPE = #{cndnType}


        and STATUS = #{status}


        and VOID_REASON = #{voidReason}


        and VOID_REMARK = #{voidRemark}


        and IS_DEBTOR_PAYMENT = #{isDebtorPayment}


       and CNDN_TIME = TO_DATE(#{cndnTime},'yyyy-MM-dd hh24:mi:ss')


ORDER BY  CREATE_TIME DESC

mapper.select:
SELECT ID, CNDN_CODE, COMPANY_ID, COMPANY_NAME, TAXATION_INVOICE_CODE, TAXATION_INVOICE, CNDN_BILL_TYPE_CODE, CNDN_BILL_TYPE_NAME, INVOICE_CODE, CUSTOMER_ID, CUSTOMER_NAME, SYS_INVOICE_CODE, ELIMINATE_AMOUNT, REMARK, CNDN_TYPE, CNDN_TIME, STATUS, VOID_REASON, VOID_REMARK, IS_DEBTOR_PAYMENT, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_FD_CREDIT_DEBIT_BILL
STATUS = 1
and SYS_INVOICE_CODE = #{sysInvoiceCode}

mapper.update:
update T_FD_CREDIT_DEBIT_BILL
set INVOICE_CODE = #{invoiceCode}
where id = #{id}

mapper.select:
SELECT t1.ID AS invoiceDetailId , t.INVOICE_AMOUNT AS eliminateAmount, t.SYS_INVOICE_CODE, t.REMARK, t.INVOICE_CODE, t.COMPANY_ID, t.COMPANY_NAME, t.CUSTOMER_ID, t.CUSTOMER_NAME, t.INVOICE_TYPE_CODE, t1.NUMBER_COUNT AS mea, t1.RATE_ITEM_CODE AS rateCode, case WHEN TO_CHAR(TBCR.RATE_ID) IS NOT NULL THEN TBCR.RATE_ID ELSE t1.RATE_ID END AS RATE_ID, t1.UNIT_CODE, t1.UNIT_NAME, t1.RATE_ITEM_NAME AS rateName, t1.TAX AS taxRate, t1.TAX_AMOUNT AS taxAmount, t1.PIECE_AMOUNT AS oldRate, t1.AMOUNT FROM T_FD_INVOICE t LEFT JOIN T_FD_INVOICE_DETAIL t1 ON t1.INVOICE_ID = t.ID LEFT JOIN T_BUS_CONTRACT_RATE TBCR ON TBCR.ID = t1.RATE_ID
t.STATUS = 1
and t.ID = #{id}
and t.COMPANY_ID = #{companyId}
and t.SYS_INVOICE_CODE = #{sysInvoiceCode}
and t.INVOICE_CODE = #{invoiceCode}
and t.CUSTOMER_ID = #{customerId}
ORDER BY t1.CREATE_TIME DESC

SELECT t1.id AS invoiceDetailId, t.ELIMINATE_AMOUNT, t.INVOICE_CODE, t.COMPANY_ID, t.COMPANY_NAME, t.CUSTOMER_ID, t.CUSTOMER_NAME, t.CNDN_TYPE CNDN_TYPE, t1.MEA, t1.RATE_CODE, t1.RATE_ID, t1.RATE_NAME, t1.UNIT_CODE, t1.UNIT_NAME, t1.OLD_RATE, t1.NEW_RATE, t1.TAX_RATE, t1.TAX_AMOUNT, t1.AMOUNT, t1.INVOICE_TYPE_CODE AS INVOICE_TYPE_CODE FROM T_FD_CREDIT_DEBIT_BILL t LEFT JOIN T_FD_CREDIT_DEBIT_BILL_DETAIL t1 ON t1.CNDN_ID = t.ID
t.STATUS = 1 AND t.CNDN_TYPE = 1 AND t.CNDN_CODE = #{sysInvoiceCode}
ORDER BY t1.CREATE_TIME DESC
